// Summary stats shown in probability bar above

// Build episode cards
const list = document.getElementById('episode-list');
EPISODES.forEach(ep => {
  const card = document.createElement('div');
  card.className = 'episode-card';
  card.id = `card-${ep.id}`;

  const isFinish = ep.outcome === 'FINISH';
  const wps = ep.wpIdx;

  // Waypoint bar
  let wpdots = '<div class="ep-waypoint-bar">';
  for (let i = 0; i < 8; i++) {
    const isLast = i === 7;
    const reached = i < wps || (isFinish && i === 7);
    const dot = `<div class="wp-dot ${isLast && isFinish ? 'finish' : (reached ? 'reached' : '')}"></div>`;
    wpdots += dot;
    if (i < 7) wpdots += `<div class="wp-dash ${reached && i < wps - 1 ? 'reached' : ''}"></div>`;
  }
  wpdots += '</div>';

  card.innerHTML = `
    <div class="ep-header">
      <span class="ep-num">EP ${ep.id + 1}</span>
      <div style="display:flex;gap:5px;align-items:center">
        <span style="font-family:'Bebas Neue',cursive;font-size:13px;letter-spacing:1px;color:${isFinish ? 'var(--accent-lime)' : ep.id === 1 ? 'var(--accent-red)' : 'var(--accent-gold)'}">
          ${ep.prob}%
        </span>
        <span class="ep-status ${isFinish ? 'status-finish' : 'status-dnf'}">
          ${isFinish ? '✓ FINISH' : '✕ DNF'}
        </span>
      </div>
    </div>
    <div class="ep-meta">
      <span>${ep.days.toFixed(1)} days</span>
      <span>${ep.avgSpeed.toFixed(1)} kt avg</span>
      <span>${(ep.dist / 1000).toFixed(1)}k nm</span>
      <span>${ep.wpIdx}/7 WP</span>
    </div>
    ${wpdots}
  `;

  card.addEventListener('click', () => loadEpisode(ep.id));
  list.appendChild(card);
});

// ============================================================
//  PLOTLY GLOBE RENDERER
// ============================================================
let currentEp = null;

function loadEpisode(id) {
  const ep = EPISODES[id];
  if (currentEp === id) return;
  currentEp = id;

  // Update cards
  document.querySelectorAll('.episode-card').forEach(c => c.classList.remove('active'));
  document.getElementById(`card-${id}`).classList.add('active');

  // Loading
  const loader = document.getElementById('loading');
  loader.classList.remove('hidden');

  // Title
  document.getElementById('ep-title').textContent = `EPISODE ${id + 1}`;
  const isFinish = ep.outcome === 'FINISH';
  document.getElementById('ep-subtitle').textContent =
    isFinish ? `✓ RACE COMPLETED IN ${ep.days.toFixed(1)} DAYS  ·  PROBABILITY ${ep.prob}%`
      : `✕ DNF — ${ep.outcomeNote || 'DID NOT FINISH'}  ·  PROBABILITY ${ep.prob}%`;

  // Stats bar
  document.getElementById('stat-days').textContent = ep.days.toFixed(1);
  document.getElementById('stat-days').className = 'stat-value highlight';

  document.getElementById('stat-dist').textContent = ep.dist.toLocaleString();

  document.getElementById('stat-speed').textContent = ep.avgSpeed.toFixed(1);

  const wpEl = document.getElementById('stat-wps');
  wpEl.textContent = `${ep.wpIdx}/7`;
  wpEl.className = 'stat-value ' + (ep.wpIdx === 7 ? 'good' : ep.wpIdx >= 4 ? 'warn' : 'bad');

  const gates = document.getElementById('stat-gates');
  const gNames = ['GOOD HOPE', 'LEEUWIN', 'CAPE HORN'];
  gates.innerHTML = ep.gates.map((g, i) =>
    `<div class="gate-chip ${g ? 'passed' : ''}">${gNames[i]}</div>`
  ).join('');

  const outEl = document.getElementById('stat-outcome');
  const outSubEl = document.getElementById('stat-outcome-sub');
  outEl.textContent = ep.outcome;
  outEl.className = 'stat-value ' + (isFinish ? 'good' : 'bad');
  outSubEl.textContent = ep.outcomeNote || (isFinish ? 'RACE COMPLETED' : '');

  // Use real route data from simulation
  const lats = ep.lats;
  const lons = ep.lons;

  // Reachable waypoints for this episode
  const reachedWPs = WAYPOINTS.slice(0, ep.wpIdx + 1);
  const lastWP = WAYPOINTS[ep.wpIdx];

  // Traces
  const traces = [];

  // Main route
  traces.push({
    type: 'scattergeo',
    lon: lons, lat: lats,
    mode: 'lines',
    line: { width: 2.5, color: isFinish ? 'rgba(0,229,255,0.85)' : 'rgba(255,120,100,0.75)' },
    name: 'Route',
    showlegend: true
  });

  // Waypoints (all)
  traces.push({
    type: 'scattergeo',
    lon: WAYPOINTS.slice(1, 8).map(w => w.lon),
    lat: WAYPOINTS.slice(1, 8).map(w => w.lat),
    mode: 'markers+text',
    marker: { size: 7, color: '#ff4444', opacity: 0.6 },
    text: ['WP1', 'WP2', 'WP3', 'WP4', 'WP5', 'WP6', 'WP7'],
    textposition: 'top center',
    textfont: { color: 'rgba(255,100,100,0.7)', size: 9 },
    name: 'Waypoints',
    showlegend: true
  });

  // Reached waypoints highlight
  if (ep.wpIdx > 0) {
    traces.push({
      type: 'scattergeo',
      lon: WAYPOINTS.slice(1, ep.wpIdx + 1).map(w => w.lon),
      lat: WAYPOINTS.slice(1, ep.wpIdx + 1).map(w => w.lat),
      mode: 'markers',
      marker: { size: 10, color: '#00e5ff', opacity: 0.9, symbol: 'circle' },
      name: 'Reached',
      showlegend: true
    });
  }

  // Start marker
  traces.push({
    type: 'scattergeo',
    lon: [WAYPOINTS[0].lon], lat: [WAYPOINTS[0].lat],
    mode: 'markers+text',
    marker: { size: 13, color: '#b0ff00', symbol: 'star' },
    text: ['START'], textposition: 'bottom center',
    textfont: { color: '#b0ff00', size: 9 },
    name: 'Start',
    showlegend: true
  });

  // End marker
  traces.push({
    type: 'scattergeo',
    lon: [lons[lons.length - 1]], lat: [lats[lats.length - 1]],
    mode: 'markers',
    marker: {
      size: 12,
      color: isFinish ? '#ffd54f' : '#ff4444',
      symbol: isFinish ? 'diamond' : 'x'
    },
    name: isFinish ? 'Finish' : 'DNF Point',
    showlegend: true
  });

  // Ice exclusion zone
  const iceLons = Array.from({ length: 37 }, (_, i) => -180 + i * 10);
  const iceLats = Array(37).fill(ICE_LIMIT);
  traces.push({
    type: 'scattergeo',
    lon: iceLons, lat: iceLats,
    mode: 'lines',
    line: { width: 1.5, color: 'rgba(120,180,255,0.4)', dash: 'dot' },
    name: 'Ice Zone (−60°)',
    showlegend: true
  });

  const layout = {
    paper_bgcolor: '#040d1a',
    plot_bgcolor: '#040d1a',
    font: { color: '#e8f4fd', family: 'Space Mono, monospace', size: 10 },
    margin: { l: 0, r: 0, t: 0, b: 0 },
    showlegend: true,
    legend: {
      x: 0.99, y: 0.04,
      xanchor: 'right',
      yanchor: 'bottom',
      bgcolor: 'rgba(4,13,26,0.75)',
      bordercolor: 'rgba(0,180,255,0.2)',
      borderwidth: 1,
      font: { size: 9, color: '#6a9bbf' }
    },
    geo: {
      projection: { type: 'orthographic', rotation: { lon: -20, lat: -20 } },
      showland: true, landcolor: 'rgb(35,35,40)',
      showocean: true, oceancolor: 'rgb(8,30,70)',
      showcoastlines: true, coastlinecolor: 'rgb(80,100,120)',
      showcountries: true, countrycolor: 'rgba(80,100,120,0.4)',
      showframe: false,
      bgcolor: '#040d1a',
    }
  };

  const config = {
    responsive: true,
    displayModeBar: true,
    displaylogo: false,
    modeBarButtonsToRemove: ['sendDataToCloud', 'editInChartStudio'],
    toImageButtonOptions: { format: 'png', filename: `vendee_ep${id}` }
  };

  setTimeout(() => {
    Plotly.react('plotly-globe', traces, layout, config).then(() => {
      loader.classList.add('hidden');
    });
  }, 50);
}

// Auto-load first episode
loadEpisode(0);